from lxml import etree
import io

def validate_xml(schema_path, xml_content):
    schema = etree.XMLSchema(etree.parse(schema_path))
    
    try:
        # Load the XML document and validate it against the schema
        doc = etree.parse(io.StringIO(xml_content))
        schema.assertValid(doc)
        
        return True  # The document is valid
    except etree.DocumentInvalid as e:
        print('XML validation error:', str(e))
        return False  # The document is not valid